户（月度额度）\nCREATE TABLE member_sms_account (\n    id BIGINT PRIMARY KEY,\n    member_id BIGINT,\n    current_month VARCHAR(7),   -- \"2025-01\" 当前月份\n    month_quota INT,            -- 当月额度（由最近购买产品决定）\n    month_used INT DEFAULT 0,   -- 当月已用\n    freeze_count INT DEFAULT 0,-- 冻结中\n    updated_at DATETIME\n);\n\n-- 短信订单（扣费）\nCREATE TABLE sms_order (\n    id BIGINT PRIMARY KEY,\n    member_id BIGINT,\n    product_id BIGINT,\n    amount DECIMAL(10,2),\n    pay_status TINYINT,         -- 0待支付 1已支付\n    pay_time DATETIME,\n    trade_no VARCHAR(64)\n);\n```\n\n> **注意**：每月1号重置 `month_used = 0`，额度由最近未过期的月包决定。\n\n### 2. 十亿级ES分片策略\n\n```json\n// bid_info索引配置（预估2亿/城市 × 30+城市 = 60亿+）\n{\n  \"settings\": {\n    \"number_of_shards\": 64,      // 按城市哈希分片\n    \"number_of_replicas\": 1,\n    \"refresh_interval\": \"30s\"   // 降低刷新频率提升写入\n  },\n  \"mappings\": {\n    \"properties\": {\n      \"id\": { \"type\": \"keyword\" },\n      \"title\": { \n        \"type\": \"text\",\n        \"analyzer\": \"ik_max_word\",\n        \"search_analyzer\": \"ik_smart\"\n      },\n      \"city_id\": { \"type\": \"keyword\" },\n      \"publish_time\": { \"type\": \"date\" }\n    }\n  }\n}\n```\n\n---\n\n## 三、任务清单修正（148个任务）\n\n```json\n{\n  \"tasks\": [\n    {\n      \"name\": \"项目骨架搭建与GoFrame v2初始化\",\n      \"description\": \"创建项目目录结构，配置go.mod，manifest/config.yaml，主入口main.go，定义各层目录(controller/service/dao/entity/library)\",\n      \"role_level\": \"max\",\n      \"batch_no\": 1,\n      \"affected_resources\": [\"go.mod\", \"main.go\", \"manifest/config.yaml\", \"internal/\"],\n      \"depends_on\": []\n    },\n    {\n      \"name\": \"GoFrame雪花ID生成器配置\",\n      \"description\": \"配置gvalid雪花ID生成器（worker_id从配置读取），封装NewSnowflake()服务\",\n      \"role_level\": \"max\",\n      \"batch_no\": 1,\n      \"affected_resources\": [\"manifest/config.yaml\", \"internal/library/id/snowflake.go\"],\n      \"depends_on\": [\"项目骨架搭建与GoFrame v2初始化\"]\n    },\n    {\n      \"name\": \"数据库连接池配置（MySQL 8.0）\",\n      \"description\": \"配置gcfg数据库连接池参数（max_open/max_idle/conn_max_lifetime），实现多数据源读写分离\",\n      \"role_level\": \"max\",\n      \"batch_no\": 1,\n      \"affected_resources\": [\"internal/dao/database.go\", \"manifest/config.yaml\"],\n      \"depends_on\": [\"项目骨架搭建与GoFrame v2初始化\"]\n    },\n    {\n      \"name\": \"Redis连接池与缓存服务封装\",\n      \"description\": \"配置gredis集群连接，封装CacheService（Get/Set/Del/Expire/MultiGet），支持gjson序列化\",\n      \"role_level\": \"max\",\n      \"batch_no\": 1,\n      \"affected_resources\": [\"internal/service/cache/cache.go\", \"manifest/config.yaml\"],\n      \"depends_on\": [\"项目骨架搭建与GoFrame v2初始化\"]\n    },\n    {\n      \"name\": \"统一响应结构与业务错误码设计\",\n      \"description\": \"定义Response<T>结构，设计错误码体系（1系统/2用户/3招标/4支付/5通知/6代理），实现统一响应中间件\",\n      \"role_level\": \"max\",\n      \"batch_no\": 1,\n      \"affected_resources\": [\"internal/library/response/response.go\", \"internal/library/ecode/ecode.go\"],\n      \"depends_on\": [\"项目骨架搭建与GoFrame v2初始化\"]\n    },\n    {\n      \"name\": \"JWT认证服务（支持多端token）\",\n      \"description\": \"实现JWT生成/解析/刷新，支持web/mp/wx三端token隔离，配置Redis黑名单\",\n      \"role_level\": \"max\",\n      \"batch_no\": 1,\n      \"affected_resources\": [\"internal/middleware/auth.go\", \"internal/service/token/token.go\"],\n      \"depends_on\": [\"统一响应结构与业务错误码设计\"]\n    },\n    {\n      \"name\": \"RBAC权限模型设计\",\n      \"description\": \"设计role/user_permission/menu表，实现接口级权限校验中间件\",\n      \"role_level\": \"pro\",\n      \"batch_no\": 1,\n      \"affected_resources\": [\"internal/model/entity/rbac.go\", \"internal/middleware/rbac.go\"],\n      \"depends_on\": [\"JWT认证服务\"]\n    },\n    {\n      \"name\": \"结构化日志与链路追踪\",\n      \"description\": \"集成zap+gf日志，配置access/business/error分级，trace_id全链路传递\",\n      \"role_level\": \"pro\",\n      \"batch_no\": 1,\n      \"affected_resources\": [\"internal/library/log/log.go\"],\n      \"depends_on\": [\"项目骨架搭建与GoFrame v2初始化\"]\n    },\n    {\n      \"name\": \"全局异常捕获与告警\",\n      \"descriptio