\"],\n      \"depends_on\": [\"招标信息主表设计\"]\n    },\n    {\n      \"name\": \"采集源配置表设计\",\n      \"description\": \"设计crawler_source表：id, name, site_url, fetch_type(api/crawl), config_json, rate_limit, status, last_fetch_time\",\n      \"role_level\": \"pro\",\n      \"batch_no\": 3,\n      \"affected_resources\": [\"manifest/sql/crawler_source.sql\", \"internal/model/entity/crawler_source.go\"],\n      \"depends_on\": [\"数据库连接池配置\"]\n    },\n    {\n      \"name\": \"阿里云OSS/COS对象存储接入\",\n      \"description\": \"封装对象存储服务（支持阿里云OSS/腾讯云COS配置化切换），文件上传/下载/预签名URL\",\n      \"role_level\": \"max\",\n      \"batch_no\": 3,\n      \"affected_resources\": [\"internal/library/storage/oss.go\", \"manifest/config.yaml\"],\n      \"depends_on\": [\"项目骨架搭建与GoFrame v2初始化\"]\n    },\n    {\n      \"name\": \"ES客户端封装与索引设计\",\n      \"description\": \"封装olivere/elastic客户端（连接池+健康检查），设计bid_info索引mapping（ik中文分词），配置高亮\",\n      \"role_level\": \"max\",\n      \"batch_no\": 3,\n      \"affected_resources\": [\"manifest/es/bid_info_mapping.json\", \"internal/service/search/es_client.go\"],\n      \"depends_on\": [\"阿里云OSS/COS对象存储接入\"]\n    },\n    {\n      \"name\": \"MySQL到ES增量同步服务\",\n      \"description\": \"实现双写机制：MySQL写入→消息队列→ES消费写入，失败重试队列保障\",\n      \"role_level\": \"max\",\n      \"batch_no\": 3,\n      \"affected_resources\": [\"internal/service/search/sync_service.go\", \"internal/service/queue/es_sync_consumer.go\"],\n      \"depends_on\": [\"ES客户端封装与索引设计\", \"招标信息主表设计\"]\n    },\n    {\n      \"name\": \"招标信息搜索服务（高亮+分页）\",\n      \"description\": \"实现ES搜索：关键词ik分词、多字段匹配(title^3+summary^2+content)、高亮标签、分页排序（时间/相关度）、城市筛选\",\n      \"role_level\": \"max\",\n      \"batch_no\": 3,\n      \"affected_resources\": [\"internal/controller/search/search.go\", \"internal/service/search/bid_search.go\"],\n      \"depends_on\": [\"MySQL到ES增量同步服务\"]\n    },\n    {\n      \"name\": \"搜索热词与建议服务\",\n      \"description\": \"搜索热词统计（Redis SortedSet），搜索建议补全（ES completion suggester）\",\n      \"role_l