x/oauth.go\", \"internal/library/wechat/mp.go\"],\n      \"depends_on\": [\"会员基础信息表设计\"]\n    },\n    {\n      \"name\": \"公众号菜单与自动回复\",\n      \"description\": \"公众号菜单配置（点击/跳转），关键词自动回复\",\n      \"role_level\": \"lite\",\n      \"batch_no\": 10,\n      \"affected_resources\": [\"internal/controller/wx/message.go\"],\n      \"depends_on\": [\"公众号网页授权登录\"]\n    },\n    {\n      \"name\": \"接口签名防篡改机制\",\n      \"description\": \"请求参数签名验证（HMAC-SHA256），防重放攻击（timestamp+nonce）\",\n      \"role_level\": \"pro\",\n      \"batch_no\": 11,\n      \"affected_resources\": [\"internal/middleware/sign.go\", \"internal/library/sign/hmac.go\"],\n      \"depends_on\": [\"统一响应结构与业务错误码设计\"]\n    },\n    {\n      \"name\": \"敏感数据脱敏处理\",\n      \"description\": \"手机号/身份证号AES加密存储，日志输出脱敏，导出加密\",\n      \"role_level\": \"pro\",\n      \"batch_no\": 11,\n      \"affected_resources\": [\"internal/library/crypto/aes.go\", \"internal/middleware/log_mask.go\"],\n      \"depends_on\": [\"结构化日志与链路追踪\"]\n    },\n    {\n      \"name\": \"SQL注入与XSS防护\",\n      \"description\": \"ORM参数化查询，输入过滤，输出转义\",\n      \"role_level\": \"lite\",\n      \"batch_no\": 11,\n      \"affected_resources\": [\"internal/middleware/security.go\"],\n      \"depends_on\": [\"参数校验封装\"]\n    },\n    {\n      \"name\": \"定时任务：订阅到期提醒\",\n      \"description\": \"每日扫描7天内到期订阅，推送续费提醒（公众号/小程序/短信）\",\n      \"role_level\": \"lite\",\n      \"batch_no\": 12,\n      \"affected_resources\": [\"internal/service/task/subscribe_remind.go\"],\n      \"depends_on\": [\"会员订阅管理接口\"]\n    },\n    {\n      \"name\": \"定时任务：代理月度结算\",\n      \"description\": \"每月1号生成本月账单明细，状态置为可提现，发送通知\",\n      \"role_level\": \"pro\",\n      \"batch_no\": 12,\n      \"affected_resources\": [\"internal/service/task/agent_settle.go\"],\n      \"depends_on\": [\"代理佣金记录表设计\"]\n    },\n    {\n      \"name\": \"定时任务：ES索引滚动\",\n      \"description\": \"按月份创建ES新索引， alias切换，冷热数据分离\",\n      \"role_level\": \"max\",\n      \"batch_no\": 12,\n      \"affected_resources\"