escription\": \"HMAC-SHA256签名验证，timestamp+nonce防重放，签名有效期5分钟\",\n      \"role_level\": \"pro\",\n      \"batch_no\": 1,\n      \"affected_resources\": [\"internal/middleware/sign.go\", \"internal/library/sign/hmac.go\"],\n      \"depends_on\": [\"统一响应结构与错误码体系\"]\n    },\n    {\n      \"name\": \"参数校验与敏感词过滤\",\n      \"description\": \"gvalid增强封装，自定义规则（手机/身份证/雪花ID），敏感词DFA算法过滤\",\n      \"role_level\": \"pro\",\n      \"batch_no\": 1,\n      \"affected_resources\": [\"internal/library/validator/validator.go\", \"internal/library/sensitive/dfa.go\"],\n      \"depends_on\": [\"统一响应结构与错误码体系\"]\n    },\n    {\n      \"name\": \"RabbitMQ连接池与延迟队列封装\",\n      \"description\": \"封装RabbitMQ连接池，实现普通队列、延迟队列（死信）、优先级队列\",\n      \"role_level\": \"max\",\n      \"batch_no\": 2,\n      \"affected_resources\": [\"internal/library/mq/rabbitmq.go\", \"internal/library/mq/delay_queue.go\"],\n      \"depends_on\": [\"多环境配置管理\"]\n    },\n    {\n      \"name\": \"消息队列生产者抽象层\",\n      \"description\": \"封装统一消息生产者接口，支持消息持久化、失败重试、顺序消息\",\n      \"role_level\": \"max\",\n      \"batch_no\": 2,\n      \"affected_resources\": [\"internal/service/mq/producer.go\", \"internal/service/mq/message.go\"],\n      \"depends_on\": [\"RabbitMQ连接池与延迟队列封装\"]\n    },\n    {\n      \"name\": \"消息队列消费者框架（并发控制）\",\n      \"description\": \"封装消费者框架，支持并发度控制、优雅关闭、消费确认、死信处理\",\n      \"role_level\": \"max\",\n      \"batch_no\": 2,\n      \"affected_resources\": [\"internal/service/mq/consumer.go\", \"internal/service/mq/consumer_pool.go\"],\n      \"depends_on\": [\"消息队列生产者抽象层\"]\n    },\n    {\n      \"name\": \"支付平台策略接口设计\",\n      \"description\": \"设计PayStrategy接口（Create/Query/Refund/Callback/Transfer），支持多平台扩展\",\n      \"role_level\": \"max\",\n      \"batch_no\": 2,\n      \"affected_resources\": [\"internal/library/pay/strategy.go\", \"internal/library/pay/manager.go\"],\n      \"depends_on\": [\"多环境配置管理\"]\n    },\n    {\n      \"name\": \"微信支付策略实现（v3）\",\n      \"description\": \"实现微信支付v3：Native/JSAPI/H5/转