/*!40000 ALTER TABLE `mvp_project` DISABLE KEYS */;
INSERT INTO `mvp_project` VALUES (315068852813697024,'招投标网','采集全网招标信息，给会员提供订阅服务。会员可以订阅多个城市的招标信息，有新招标入网自动通知。提供投标信息文档下载。','1','','采集全网招标信息，给会员提供订阅服务。会员可以订阅多个城市的招标信息，有新招标入网自动通知，短信通知，公众号通知，小程序通知，短信通知需要购买短信包。提供投标信息文档下载。搜索需要标题摘要内容高亮显示。亿级项目，使用goframe v2框架做。规划的时候可以使用goframe v2的Skills。本项目有渠道代理功能，渠道代理可以被超级管理员设置渠道收入比例，有三级。换提供表标书模板下载等',2,NULL,1000000000000000003,1000000000000000001,'2026-04-02 08:24:28','2026-04-02 09:21:56','2026-04-02 09:21:56'),(315076929772326912,'招投标网','采集全网招标信息，给会员提供订阅服务。会员可以订阅多个城市的招标信息，有新招标入网自动通知，短信通知，公众号通知，小程序通知，短信通知需要购买短信包。提供投标信息文档下载。搜索需要标题摘要内容高亮显示。亿级项目，使用goframe v2框架做。规划的时候可以使用goframe v2的Skills。本项目有渠道代理功能，渠道代理可以被超级管理员设置渠道收入比例，有三级。换提供表标书模板下载等','paused','测试',NULL,315100000000000001,NULL,1000000000000000003,1000000000000000001,'2026-04-02 08:56:34','2026-04-02 10:55:51',NULL);
