DROP TABLE IF EXISTS `mvp_role_preset`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `mvp_role_preset` (
  `id` bigint unsigned NOT NULL COMMENT '雪花ID',
  `role_type` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '角色类型：architect/implementer/auditor/coordinator',
  `role_level` varchar(10) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '角色等级：lite/pro/max',
  `model_id` bigint unsigned NOT NULL COMMENT 'AI模型ID',
  `system_prompt` text COLLATE utf8mb4_general_ci COMMENT '默认系统提示词（角色设定）',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '状态:0=禁用,1=启用',
  `sort` int NOT NULL DEFAULT '0' COMMENT '排序',
  `created_by` bigint unsigned DEFAULT NULL COMMENT '创建人ID',
  `dept_id` bigint unsigned DEFAULT NULL COMMENT '所属部门ID',
  `created_at` datetime DEFAULT NULL COMMENT '创建时间',
  `updated_at` datetime DEFAULT NULL COMMENT '更新时间',
  `deleted_at` datetime DEFAULT NULL COMMENT '软删除时间',
  PRIMARY KEY (`id`),
  KEY `idx_deleted_at` (`deleted_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='角色预设模板';
/*!40101 SET character_set_client = @saved_cs_client */;

